export interface TrackPartInfoProperties extends Partial<Pick<TrackPartInfo, "labelsVisible" | "visible">> {
  /**
   * Defines labels for the track part as an array of
   * [LabelClass](https://developers.arcgis.com/javascript/latest/references/core/layers/support/LabelClass/). When set, labels
   * independent of the [layer.labelingInfo](https://developers.arcgis.com/javascript/latest/references/core/layers/FeatureLayer/#labelingInfo) are used
   * to convey information about the track.
   *
   * Any aggregate field defined in [TrackInfo.fields](https://developers.arcgis.com/javascript/latest/references/core/layers/support/TrackInfo/#fields) can be referenced in the label.
   *
   * Multiple Label classes with different `where` clauses can be used to define several
   * labels with varying styles on the same track part. Likewise, multiple label classes
   * may be used to label different types of track parts (e.g. green labels
   * for fast observations and red labels for slow observations).
   *
   * @example
   * // Displays the observation count of the track
   * layer.trackInfo = {
   *   fields: [{
   *     name: "total_observations",
   *     statisticType: "count"
   *   }],
   *   trackLines: {
   *     labelingInfo: [{
   *       labelExpressionInfo: {
   *         expression: "$feature.total_observations"
   *       },
   *       symbol: {
   *         type: "text",
   *         color: "white",
   *         font: {
   *           size: "12px"
   *         },
   *         haloSize: 1,
   *         haloColor: "black"
   *       }
   *     }]
   *   }
   * };
   */
  labelingInfo?: LabelClassProperties[] | null;
  /**
   * The renderer used to style the track part. Depending on the renderer type,
   * features may be visualized with the same symbol or with varying symbols
   * based on the values of the provided fields.
   *
   * @example
   * layer.trackInfo = {
   *   previousObservations: {
   *     renderer: {
   *        type: "simple",  // autocasts as new SimpleRenderer()
   *        symbol: {
   *          type: "simple-marker",  // autocasts as new SimpleFillSymbol()
   *          outline: {  // autocasts as new SimpleLineSymbol()
   *            width: 0.5,
   *            color: "white"
   *          }
   *        },
   *        visualVariables: [{
   *          type: "color",
   *          field: "speed",
   *          stops: [
   *            { value: 5, color: "red" },
   *            { value: 45, color: "green" }
   *          ]
   *        }]
   *     }
   *   }
   * };
   */
  renderer?: (((SimpleRendererProperties & { type: "simple" }) | (ClassBreaksRendererProperties & { type: "class-breaks" }) | (UniqueValueRendererProperties & { type: "unique-value" }) | (DotDensityRendererProperties & { type: "dot-density" }) | (DictionaryRendererProperties & { type: "dictionary" }) | (PieChartRendererProperties & { type: "pie-chart" })) | (HeatmapRendererProperties & { type: "heatmap" })) | null;
}

